import json
from pathlib import Path

p = Path('notes/_notion_raw/Monte Carlo Tree Search A Review of Recent Modifications and Applications.json')
data = json.loads(p.read_text(encoding='utf-8'))
blocks = data['blocks']
root_id = data['page_id']

def block_value(entry):
    if not isinstance(entry, dict):
        return {}
    if isinstance(entry.get('value'), dict) and isinstance(entry['value'].get('value'), dict):
        return entry['value']['value']
    if isinstance(entry.get('value'), dict):
        return entry['value']
    return {}

def rich_plain(parts):
    if not parts:
        return ''
    out=[]
    for seg in parts:
        if isinstance(seg, list) and seg:
            text=seg[0]
            if isinstance(text,str):
                out.append(text)
    return ''.join(out).strip()

def prop_plain(v,key):
    return rich_plain((v.get('properties') or {}).get(key))

def block_title(v):
    return prop_plain(v,'title')

def block_url(v):
    fmt=v.get('format') or {}
    props=v.get('properties') or {}
    for k in ('display_source','source'):
        if isinstance(fmt.get(k),str) and fmt.get(k):
            return fmt[k]
    for k in ('source','link','url'):
