Run $p='D:\paper_reading\paper_reading\notes\Hyena Hierarchy.md'
$src=Get-Content -Encoding UTF8 $p
$out=New-Object System.Collections.Generic.List[string]
for($i=0;$i -lt $src.Count;$i++){
  $line=$src[$i]

  # drop TeX macro-definition noise imported from LaTeX preamble
  if($line -match '^\s*-?\s*\\newcommand\{\\s[A-Z]\}'){ continue }

  # normalize equation block delimiters
  if($line -match '^\s*-?\s*\\begin\{equation\*?\}\s*$'){ $out.Add('$$'); continue }
  if($line -match '^\s*-?\s*\\end\{equation\*?\}\s*$'){ $out.Add('$$'); continue }

  # convert broken single-dollar lines
  if($line.Trim() -eq '$'){ $out.Add('$$'); continue }

  # combine perplexity two-line formula
  if($line -match '^\s*-\s*\\text\{Perplexity\}\(P\)\s*=\s*2\^\{H\(P\)\}\\\\\s*$'){
    $next=''
    if($i+1 -lt $src.Count){ $next=$src[$i+1].Trim() }
    if($next -match '^H\(P\)\s*='){
      $out.Add('$$\text{Perplexity}(P) = 2^{H(P)}\\')
      $out.Add($next)
      $out.Add('$$')
      $i++
      continue
    }
  }

  # wrap common one-line equations
  if($line -match '^\s*-\s*(y_t = \(h \* u\)_t = .*)$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(\\begin\{aligned\}.*\\end\{aligned\})\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(\\begin\{align\*\}.*\\end\{align\*\})\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(D_H=diag\(H\))\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(y = x\^N .*?)\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(x_tu_t = .*?)\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(\\begin\{aligned\}\s*A\(q,k\).*?)\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(y = H\(u\)v = .*?)\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(h_t = \{\\sf Window\}\(t\).*?)\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }
  if($line -match '^\s*-\s*(\\mathcal\{O\}\(.*\))\s*$'){ $out.Add('$$'+$Matches[1]+'$$'); continue }

  $out.Add($line)
}

$content = ($out -join "`r`n")

# replace LaTeX shorthand symbols from source with explicit bold matrices for Obsidian rendering
$content = $content -replace '\\sA','\\mathbf{A}'
$content = $content -replace '\\sB','\\mathbf{B}'
$content = $content -replace '\\sC','\\mathbf{C}'
$content = $content -replace '\\sD','\\mathbf{D}'
$content = $content -replace '\\sS','\\mathbf{S}'
$content = $content -replace '\\sW','\\mathbf{W}'
$content = $content -replace '\\sM','\\mathbf{M}'

# second pass: ensure aligned blocks are closed and collapse duplicate $$ lines
$lines2 = $content -split "`r?`n"
$fixed = New-Object System.Collections.Generic.List[string]
$inAligned = $false
foreach($ln in $lines2){
  $t = $ln.Trim()
  if($t -match '^\\begin\{aligned\}') { $inAligned = $true }
  if($t -eq '$$' -and $inAligned){
    $fixed.Add('\\end{aligned}')
    $inAligned = $false
  }
  if($t -eq '$$' -and $fixed.Count -gt 0 -and $fixed[$fixed.Count-1].Trim() -eq '$$'){
    continue
  }
  $fixed.Add($ln)
  if($t -match '^\\end\{aligned\}') { $inAligned = $false }
}

Set-Content -Encoding UTF8 $p ($fixed -join "`r`n")
'updated'

