 if($trim -eq '\begin{aligned}'){
   $prev=''; for($j=$out.Count-1;$j -ge 0;$j--){ if($out[$j].Trim() -ne ''){ $prev=$out[$j].Trim(); break } }
   if($prev -ne '$$'){ $out.Add('$$\begin{aligned}'); continue }
 }
 $out.Add($line)
}; Set-Content -Encoding UTF8 $p ($out -join "`r`n"); 'fixed4'

