content.title:
Run $p='D:\paper_reading\paper_reading\notes\Hyena Hierarchy.md'; $c=Get-Content -Raw -Encoding UTF8 $p;
# reduce accidental doubled backslashes for TeX commands only
$c=[regex]::Replace($c,'\\\\([A-Za-z])','\\$1');
# normalize aligned block starts
$c=[regex]::Replace($c,'(?m)^\\begin\{aligned\}\s*$','$$\\begin{aligned}');
# collapse accidental duplicated opening $$ before aligned blocks
$c=[regex]::Replace($c,'\$\$\r?\n\$\$\\begin\{aligned\}','$$\\begin{aligned}');
# merge two-line t\mapsto blocks into one equation block
$c=[regex]::Replace($c,'(?ms)^\$t\\mapsto h_t\s*=\s*(.*?)\r?\n\$\$\s*','$$t\\mapsto h_t = $1$$' + "`r`n");
Set-Content -Encoding UTF8 $p $c; 'fixed5'

