content.title:
Run $p='D:\paper_reading\paper_reading\notes\Hyena Hierarchy.md'; $c=Get-Content -Raw -Encoding UTF8 $p; $c=$c.Replace('\\begin','\begin').Replace('\\end','\end').Replace('\\mapsto','\mapsto').Replace('\\mathbf','\mathbf'); Set-Content -Encoding UTF8 $p $c; 
$src=Get-Content -Encoding UTF8 $p; $out=New-Object System.Collections.Generic.List[string]; for($i=0;$i -lt $src.Count;$i++){ $line=$src[$i]; $trim=$line.Trim();
  if($trim -like '$t\mapsto h_t*' -and $i+1 -lt $src.Count -and $src[$i+1].Trim() -eq '$$'){ $out.Add('$$'+$trim.Substring(1)+'$$'); $i++; continue }
  if($trim -eq '\begin{aligned}'){
    $prev=''; for($j=$out.Count-1;$j -ge 0;$j--){ if($out[$j].Trim() -ne ''){ $prev=$out[$j].Trim(); break } }
    if($prev -ne '$$'){ $out.Add('$$'); $out.Add('\begin{aligned}'); continue }
  }
  $out.Add($line)
}; Set-Content -Encoding UTF8 $p ($out -join "`r`n"); 'fixed6'

